1908:     private int deleteRetentionMsBreachedSegments() throws IOException {
1909:         long retentionMs = UnifiedLog.localRetentionMs(config(), remoteLogEnabledAndRemoteCopyEnabled());
1910:         if (retentionMs < 0) return 0;
1911:         long startMs = time().milliseconds();
1912: 
1913:         DeletionCondition shouldDelete = (segment, nextSegmentOpt) -> {
1914:             if (startMs < segment.largestTimestamp()) {
1915:                 futureTimestampLogger.warn("{} contains future timestamp(s), making it ineligible to be deleted", segment);
1916:             }
1917:             boolean delete = startMs - segment.largestTimestamp() > retentionMs;
1918:             logger.debug("{} retentionMs breached: {}, startMs={}, retentionMs={}",
1919:                     segment, delete, startMs, retentionMs);
1920:             return delete;
1921:         };
1922:         return deleteOldSegments(shouldDelete, toDelete -> {
